import { readFileSync } from "node:fs";
import { describe, expect, it } from "vitest";

describe("Next.js + Tailwind skeleton matches the CTO architecture", () => {
  it("package.json declares Next 14, React 18, Tailwind 3, drizzle-orm runtime, and a vitest dev dep", () => {
    const pkg = JSON.parse(readFileSync("./package.json", "utf-8"));
    expect(pkg.dependencies.next).toMatch(/^\^?14\./);
    expect(pkg.dependencies.react).toMatch(/^\^?18\./);
    expect(pkg.dependencies["react-dom"]).toMatch(/^\^?18\./);
    expect(pkg.dependencies["drizzle-orm"]).toBeDefined();
    expect(pkg.devDependencies.tailwindcss).toMatch(/^\^?3\./);
    expect(pkg.devDependencies.typescript).toMatch(/^\^?5\./);
    expect(pkg.devDependencies.vitest).toBeDefined();
  });

  it("package.json scripts cover dev / build / start / test", () => {
    const pkg = JSON.parse(readFileSync("./package.json", "utf-8"));
    expect(pkg.scripts.dev).toBe("next dev");
    expect(pkg.scripts.build).toBe("next build");
    expect(pkg.scripts.start).toBe("next start");
    expect(pkg.scripts.test).toBe("vitest run");
  });

  it("tsconfig.json maps the @/ path alias to repo root and enables strict + bundler resolution", () => {
    const ts = JSON.parse(readFileSync("./tsconfig.json", "utf-8"));
    expect(ts.compilerOptions.strict).toBe(true);
    expect(ts.compilerOptions.moduleResolution).toBe("bundler");
    expect(ts.compilerOptions.jsx).toBe("preserve");
    expect(ts.compilerOptions.paths["@/*"]).toEqual(["./*"]);
  });

  it("tailwind config scans app/ for ts and tsx files", () => {
    const cfg = readFileSync("./tailwind.config.ts", "utf-8");
    expect(cfg).toMatch(/content.*\.\/app\/\*\*/);
  });

  it("next-env.d.ts ships the standard Next.js type references", () => {
    const env = readFileSync("./next-env.d.ts", "utf-8");
    expect(env).toMatch(/<reference types="next" \/>/);
    expect(env).toMatch(/<reference types="next\/image-types\/global" \/>/);
  });
});
